const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const crypto = require('crypto');

const app = express();

// Ensure upload directory exists
const UPLOAD_DIR = path.join(__dirname, 'uploads');
if (!fs.existsSync(UPLOAD_DIR)) {
  fs.mkdirSync(UPLOAD_DIR, { recursive: true });
}

// Allowed file types (whitelist approach)
const ALLOWED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'application/pdf',
  'text/plain',
];

const ALLOWED_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.pdf', '.txt'];

// Max file size: 5MB
const MAX_FILE_SIZE = 5 * 1024 * 1024;

// File filter to validate uploads
const fileFilter = (req, file, cb) => {
  const ext = path.extname(file.originalname).toLowerCase();

  if (!ALLOWED_MIME_TYPES.includes(file.mimetype)) {
    return cb(new Error('File type not allowed (invalid MIME type)'), false);
  }

  if (!ALLOWED_EXTENSIONS.includes(ext)) {
    return cb(new Error('File extension not allowed'), false);
  }

  cb(null, true);
};

// Storage configuration with secure filename generation
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, UPLOAD_DIR);
  },
  filename: (req, file, cb) => {
    // Generate a random filename to prevent path traversal and overwrite attacks
    const randomName = crypto.randomBytes(32).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();
    cb(null, `${randomName}${ext}`);
  },
});

const upload = multer({
  storage: storage,
  limits: {
    fileSize: MAX_FILE_SIZE,
    files: 5, // Max number of files per request
    fields: 10, // Max number of non-file fields
    fieldNameSize: 100, // Max field name size
    fieldSize: 1024, // Max field value size
  },
  fileFilter: fileFilter,
});

// Single file upload endpoint
app.post('/upload', (req, res) => {
  const singleUpload = upload.single('file');

  singleUpload(req, res, (err) => {
    if (err instanceof multer.MulterError) {
      if (err.code === 'LIMIT_FILE_SIZE') {
        return res.status(413).json({ error: 'File size exceeds the limit of 5MB' });
      }
      if (err.code === 'LIMIT_FILE_COUNT') {
        return res.status(400).json({ error: 'Too many files uploaded' });
      }
      return res.status(400).json({ error: `Upload error: ${err.message}` });
    }

    if (err) {
      return res.status(400).json({ error: err.message });
    }

    if (!req.file) {
      return res.status(400).json({ error: 'No file provided' });
    }

    // Verify the file was saved within the expected directory (prevent path traversal)
    const resolvedPath = path.resolve(req.file.path);
    if (!resolvedPath.startsWith(path.resolve(UPLOAD_DIR))) {
      // Remove the file if it was saved outside the upload directory
      try {
        fs.unlinkSync(resolvedPath);
      } catch (unlinkErr) {
        console.error('Failed to remove suspicious file:', unlinkErr.message);
      }
      return res.status(400).json({ error: 'Invalid file path detected' });
    }

    return res.status(200).json({
      message: 'File uploaded successfully',
      filename: req.file.filename,
      size: req.file.size,
      mimetype: req.file.mimetype,
    });
  });
});

// Multiple file upload endpoint
app.post('/upload-multiple', (req, res) => {
  const multiUpload = upload.array('files', 5);

  multiUpload(req, res, (err) => {
    if (err instanceof multer.MulterError) {
      if (err.code === 'LIMIT_FILE_SIZE') {
        return res.status(413).json({ error: 'File size exceeds the limit of 5MB' });
      }
      if (err.code === 'LIMIT_UNEXPECTED_FILE') {
        return res.status(400).json({ error: 'Too many files. Maximum is 5.' });
      }
      return res.status(400).json({ error: `Upload error: ${err.message}` });
    }

    if (err) {
      return res.status(400).json({ error: err.message });
    }

    if (!req.files || req.files.length === 0) {
      return res.status(400).json({ error: 'No files provided' });
    }

    // Verify all files are within the upload directory
    for (const file of req.files) {
      const resolvedPath = path.resolve(file.path);
      if (!resolvedPath.startsWith(path.resolve(UPLOAD_DIR))) {
        // Clean up all uploaded files
        req.files.forEach((f) => {
          try {
            fs.unlinkSync(path.resolve(f.path));
          } catch (unlinkErr) {
            console.error('Failed to remove suspicious file:', unlinkErr.message);
          }
        });
        return res.status(400).json({ error: 'Invalid file path detected' });
      }
    }

    const uploadedFiles = req.files.map((file) => ({
      filename: file.filename,
      size: file.size,
      mimetype: file.mimetype,
    }));

    return res.status(200).json({
      message: `${req.files.length} file(s) uploaded successfully`,
      files: uploadedFiles,
    });
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err.message);
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`File upload server running on port ${PORT}`);
});

module.exports = app;